INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Bare-metal and virtual compute$q$, $q$Dedibox dedicated servers alongside virtual instances across Development, General Purpose, Compute Optimized, and Memory Optimized ranges.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$GPU and AI infrastructure$q$, $q$GPU instances designed for AI training and inference workloads, part of Scaleway's push into sovereign AI infrastructure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Managed Kubernetes and containers$q$, $q$Fully managed Kubernetes clusters and serverless container and function offerings for cloud-native applications.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Object and block storage$q$, $q$S3-compatible object storage and block storage volumes for persistent data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Managed databases$q$, $q$Managed PostgreSQL, MySQL, and Redis-compatible database services with automated backups and scaling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Networking tools$q$, $q$Load balancers, private networks, and VPC-style isolation for securing cloud architectures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$European data residency$q$, $q$Data centers located in Paris, Amsterdam, and Warsaw to support GDPR compliance and data sovereignty needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Per-second billing$q$, $q$Usage-based pricing billed by the second on most compute products, avoiding long-term lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Transparent, usage-based pricing with no long-term commitment required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$European data centers support GDPR and data sovereignty requirements$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Broad product range spanning bare metal to managed Kubernetes and AI GPUs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Backed by the well-capitalized Iliad Group, providing financial stability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Competitive pricing versus AWS, Google Cloud, and Azure for comparable resources$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Smaller global data center footprint than the major US hyperscalers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Fewer managed service integrations and third-party marketplace tools than AWS or Azure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Documentation and community support are smaller in scale than larger providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Some advanced enterprise features require contacting sales rather than self-service$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Where is Scaleway headquartered$q$, $q$Scaleway is headquartered in Paris, France, and is a majority-owned subsidiary of the Iliad Group.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$When was Scaleway founded$q$, $q$Scaleway's parent company began as Online SAS in 1999; the cloud infrastructure business was rebranded as Scaleway in April 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$How does Scaleway pricing work$q$, $q$Scaleway uses pay-as-you-go, usage-based pricing billed per second for most cloud compute products, with dedicated Dedibox servers starting around EUR 4.99 per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Is Scaleway a good alternative to AWS or Google Cloud$q$, $q$Scaleway is often chosen by European companies seeking GDPR-friendly data residency and simpler, more transparent pricing than the major US hyperscalers, though it has a smaller global footprint.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Does Scaleway offer GPU instances for AI$q$, $q$Yes, Scaleway offers GPU instances designed for AI training and inference as part of its expanding AI infrastructure lineup.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Who owns Scaleway$q$, $q$Scaleway is a majority-owned subsidiary of the Iliad Group, the French telecom conglomerate founded by Xavier Niel.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Does Scaleway offer managed Kubernetes$q$, $q$Yes, Scaleway provides managed Kubernetes clusters as well as serverless container and function services.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$European data-sovereign hosting$q$, $q$Companies that need to keep customer data within EU data centers for GDPR compliance can host workloads on Scaleway's Paris, Amsterdam, or Warsaw infrastructure.$q$, $q$European SaaS companies and regulated industries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$AI and GPU workloads$q$, $q$Teams training or running inference for machine learning models can use Scaleway's GPU instances as a lower-cost alternative to hyperscaler GPU pricing.$q$, $q$AI startups and data science teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$General cloud application hosting$q$, $q$Startups and developers can run virtual machines, managed databases, Kubernetes, and object storage for typical web and application workloads.$q$, $q$Developers and DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Dedibox Dedicated Servers$q$, $q$From about EUR 4.99/month$q$, $q$monthly$q$, NULL, $q$["Bare-metal dedicated server","Available across 60 global locations","No long-term contract required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$Cloud Compute Instances$q$, $q$Usage-based, per-second billing$q$, $q$pay-as-you-go$q$, NULL, $q$["Development, General Purpose, Compute Optimized, and Memory Optimized instance ranges","Per-second billing","Scalable up or down on demand"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$GPU Instances$q$, $q$Usage-based, varies by GPU type$q$, $q$pay-as-you-go$q$, NULL, $q$["GPU instances for AI training and inference","Per-second billing","Suited for machine learning workloads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scaleway is a cloud infrastructure provider based in Paris, France, and a subsidiary of the Iliad Group. Originally founded in 1999 as Online SAS, the company rebranded its cloud arm as Scaleway in 2015 and has since built a full public cloud platform spanning compute, storage, networking, AI, and managed services, serving tens of thousands of businesses worldwide.$q$, $q$Scaleway positions itself as a European alternative to the US hyperscalers, emphasizing data sovereignty, GDPR compliance, and transparent pricing. It operates its own data centers in France, the Netherlands, and Poland.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scaleway's core offerings include bare-metal Dedibox dedicated servers, virtual compute instances across several performance tiers, managed Kubernetes and container services, serverless functions, object and block storage, managed databases, and networking tools like load balancers and private networks.$q$, $q$In recent years Scaleway has expanded aggressively into AI infrastructure, offering GPU instances for training and inference and pursuing acquisitions such as data platform company Saagie to strengthen its AI and data engineering stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71f03e14-432c-435c-8c0e-ef2bed2b9907', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scaleway uses a pay-as-you-go, usage-based pricing model with per-second billing on most cloud compute resources, meaning customers only pay for what they use without long-term commitments. Dedicated Dedibox servers start at roughly EUR 4.99 per month, while cloud instance pricing varies by CPU, memory, and GPU configuration.$q$, $q$The company markets its pricing as transparent and predictable, without the hidden egress fees and complex tiering often associated with larger cloud providers, though exact costs still depend on the specific product line and region selected.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Personalized attendee scheduling$q$, $q$Attendees can browse sessions and build their own personalized agenda across multiple concurrent tracks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Speaker and session profiles$q$, $q$Dedicated profile pages for speakers and sessions to showcase bios, topics, and materials.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Registration and ticketing$q$, $q$Built-in registration and ticketing tools, with reduced ticketing fees on higher-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Call for papers / session submissions$q$, $q$Workflows for collecting and reviewing speaker session proposals, with advanced options on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Sponsor and exhibitor tools$q$, $q$Sponsor profile pages and lead retrieval tools to help sponsors capture attendee engagement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Web and mobile event app$q$, $q$A branded web and mobile app attendees use to view the schedule, network, and receive updates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Attendance tracking and badges$q$, $q$Customizable badge printing and attendance tracking available on Boost and higher plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Custom reporting$q$, $q$Advanced, custom reporting tools available on the Ultra plan for post-event analysis.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Purpose-built for multi-track conferences and event agendas rather than generic scheduling$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Personalized attendee scheduling app improves the on-site experience$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Sponsor and lead retrieval tools support event monetization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Discounts available for nonprofits, education, government, and startups$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Free or low-cost options for smaller events under about 50 attendees$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Pricing is structured as annual plans, which can be a larger upfront commitment than monthly SaaS tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Advanced features like custom reporting and priority support are reserved for the top Ultra tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Enterprise features such as on-premise hosting require custom sales conversations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Less suited to simple one-on-one appointment scheduling than dedicated booking tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$What is Sched used for$q$, $q$Sched is used to build and publish schedules for conferences, conventions, and festivals, letting attendees create personalized agendas and organizers manage speakers, sponsors, and registration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$How much does Sched cost$q$, $q$Sched's Launch plan starts at roughly $600 per year, Boost is about $1,500 per year, and Ultra is about $3,900 per year, with custom Enterprise pricing available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Does Sched offer a free trial$q$, $q$Yes, Sched offers a 30-day free trial and a 60-day money-back guarantee on paid plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Is Sched suitable for small events$q$, $q$Yes, Sched offers free or reduced pricing for smaller events, generally under about 50 attendees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Does Sched support virtual and hybrid events$q$, $q$Yes, Sched supports in-person, virtual, and hybrid event formats through its web and mobile app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$When was Sched founded$q$, $q$Sched was founded in 2008 and is headquartered in Los Angeles, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Does Sched offer discounts$q$, $q$Yes, Sched offers discounts for nonprofits (up to 50 percent), education (33 percent), government (17 percent), and startups (17 percent).$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Multi-track conference scheduling$q$, $q$Organizers publish a full multi-day, multi-track agenda and let attendees build personalized schedules across sessions.$q$, $q$Conference and convention organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Sponsor and exhibitor lead capture$q$, $q$Sponsors and exhibitors use Sched's lead retrieval tools to capture and follow up with engaged attendees.$q$, $q$Event sponsors and exhibitors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Speaker and session management$q$, $q$Event teams collect speaker submissions through call-for-papers workflows and publish speaker profile pages.$q$, $q$Event program committees$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Launch$q$, $q$About $600/year$q$, $q$annual$q$, NULL, $q$["Unlimited events","Web and mobile app","Scheduling tools and speaker profiles","Registration and ticketing","Basic call for papers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Boost$q$, $q$About $1,500/year$q$, $q$annual$q$, NULL, $q$["Everything in Launch","Attendee networking","Attendance tracking","Customizable badges","Sponsor profiles and lead retrieval"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Ultra$q$, $q$About $3,900/year$q$, $q$annual$q$, NULL, $q$["Everything in Boost","Onboarding and training","Priority support","Custom reporting","Secret sessions and advanced lead retrieval"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["On-premise hosting","Custom features","Dedicated premium agent support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sched is event scheduling and agenda-management software founded in 2008 and headquartered in Los Angeles, California. It is designed for organizers of conferences, conventions, and festivals who need to publish multi-track schedules, manage speakers and sponsors, and let attendees build personalized agendas.$q$, $q$The platform serves both in-person and virtual/hybrid events, with a companion web and mobile app that attendees use to browse sessions, bookmark talks, and build their own schedule.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Sched provides personalized scheduling, speaker and session profile pages, registration and ticketing, call-for-papers/session submission tools, attendee networking, customizable badges, and sponsor/exhibitor profiles.$q$, $q$Higher tiers add attendance tracking, lead retrieval for sponsors, advanced call-for-papers workflows, custom reporting, and dedicated onboarding and training support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddaae47-3573-4276-bcc8-70bfee3048e2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sched is priced as annual plans rather than simple monthly subscriptions: Launch starts around $600 per year, Boost around $1,500 per year, and Ultra around $3,900 per year, with an Enterprise tier available at custom pricing for on-premise or highly customized deployments.$q$, $q$Discounts are available for nonprofits, educational institutions, government organizations, and startups, and Sched offers a 30-day free trial along with a 60-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Property-based test generation$q$, $q$Automatically generates diverse API test cases from OpenAPI and GraphQL schemas using the Hypothesis testing engine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Schema conformance validation$q$, $q$Checks that live API responses match the constraints and types defined in the schema specification.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Schema-aware fuzzing$q$, $q$Probes boundary values and constraint violations derived directly from the API schema.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$CI/CD integration$q$, $q$Official integrations with GitHub Actions, GitLab CI, and pytest for automated testing pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Multiple deployment options$q$, $q$Available as a Python package, Docker image, or standalone CLI tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Reproducible failure reports$q$, $q$Generates curl commands and minimal reproduction cases to speed up debugging of failing tests.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Workbench cloud dashboard$q$, $q$A paid cloud offering for continuous API fuzzing monitoring beyond one-off CI runs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$TraceCov coverage analytics$q$, $q$A paid tool for measuring schema-level test coverage against an OpenAPI specification.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Core tool is completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Automatically generates large numbers of edge-case tests without manual scripting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Proven to catch more defects than some alternative tools in academic research$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Strong CI/CD integration with GitHub Actions, GitLab CI, and pytest$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Adopted by major engineering organizations, indicating production reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Requires an accurate, well-maintained OpenAPI or GraphQL schema to be effective$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Pricing for the paid Workbench and TraceCov cloud offerings is not publicly listed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Primarily oriented toward Python-centric and CI-based workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Learning curve for teams unfamiliar with property-based testing concepts$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Is Schemathesis free$q$, $q$Yes, the core Schemathesis API testing tool is free and open source; paid cloud add-ons called Workbench and TraceCov are also available.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$What does Schemathesis test$q$, $q$Schemathesis tests REST APIs defined by OpenAPI schemas and GraphQL APIs by automatically generating test cases from the schema and checking for spec violations and bugs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$How does Schemathesis generate test cases$q$, $q$It uses the Hypothesis property-based testing library to generate diverse, schema-constrained inputs, including boundary and edge cases, automatically.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Does Schemathesis integrate with CI/CD$q$, $q$Yes, it has official integrations with GitHub Actions, GitLab CI, and pytest for automated testing in continuous integration pipelines.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Who uses Schemathesis$q$, $q$Companies including Spotify, JetBrains, Red Hat, Netflix, SAP, IBM, and Capital One have used or written about using Schemathesis.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$What is Schemathesis Workbench$q$, $q$Workbench is a paid cloud dashboard for continuous API fuzzing monitoring, offered alongside the free open-source core tool.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Can Schemathesis test GraphQL APIs$q$, $q$Yes, Schemathesis supports generating tests from both OpenAPI and GraphQL schema definitions.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Automated API regression testing$q$, $q$Engineering teams run Schemathesis in CI to automatically catch schema violations and regressions before deployment.$q$, $q$Backend and QA engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Pre-release API fuzz testing$q$, $q$Teams use schema-driven fuzzing to find edge-case bugs and boundary violations before shipping an API to production.$q$, $q$API platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Continuous API monitoring$q$, $q$Organizations use the paid Workbench cloud dashboard to continuously monitor live APIs for schema drift and failures.$q$, $q$DevOps and platform reliability teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Property-based test generation from OpenAPI/GraphQL schemas","CLI, pytest, and Docker usage","GitHub Actions and GitLab CI integration","Reproducible failure reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$Workbench$q$, $q$Not publicly listed$q$, $q$contact for pricing$q$, NULL, $q$["Cloud-based API fuzzing dashboard","Continuous monitoring of API behavior"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$TraceCov$q$, $q$Not publicly listed$q$, $q$contact for pricing$q$, NULL, $q$["Schema-level test coverage analytics for OpenAPI specs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Schemathesis is an open-source API testing tool that uses property-based testing to automatically generate test cases from OpenAPI and GraphQL schema definitions, rather than requiring engineers to write individual test scenarios by hand.$q$, $q$Built on the Hypothesis testing library, it is used by engineering teams at companies including Spotify, JetBrains, Red Hat, and Capital One to catch schema violations, edge-case bugs, and spec inconsistencies before they reach production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The tool generates diverse, schema-aware test inputs automatically, validates that API responses conform to the OpenAPI or GraphQL specification, and performs schema-driven fuzzing to probe boundary values and constraint violations.$q$, $q$It integrates with pytest, the command line, Docker, and CI systems like GitHub Actions and GitLab CI, and produces reproducible failure reports including curl commands for easy debugging.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Schemathesis tool is free and open source, available via pip, Docker, or a GitHub Action with no licensing cost for standard API testing use.$q$, $q$Schemathesis also offers paid cloud add-ons, Workbench (an API fuzzing dashboard for continuous monitoring) and TraceCov (schema-level coverage analytics), though specific pricing for these commercial services is not published and requires contacting the company directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5da7c24e-f64f-46b1-a907-d8b6683f3c73', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Automatic GPG encryption and decryption$q$, $q$Handles OpenPGP encryption and decryption of list traffic automatically so subscribers do not need to manage keys per message.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Remailing to non-subscribers$q$, $q$Can receive and forward encrypted messages to and from people who are not list subscribers, re-encrypting as needed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Header stripping and format conversion$q$, $q$Strips potentially identifying headers and normalizes message formats to reduce metadata leakage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Optional web interface$q$, $q$Version 3's API can power schleuder-web, an optional browser-based interface for list administration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Self-hosted deployment$q$, $q$Runs on your own infrastructure, with packages available for Debian, CentOS, and Arch Linux.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Internationalized, robust core$q$, $q$The version 3 rewrite focused on robustness and internationalization for broader adoption.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Strong end-to-end encryption model for sensitive group communication$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Can safely bridge encrypted communication with non-subscribers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Available as prebuilt packages for major Linux distributions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Backed by an established privacy-tooling community (0xacab.org / Riseup infrastructure)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Requires self-hosting and server administration skills to deploy$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$No commercial support, SLA, or vendor to contact for help$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$No official cloud-hosted version offered by the project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Smaller user base and documentation compared to mainstream mailing list tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Ongoing GPG key management still required at the list-admin level$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Is Schleuder free to use$q$, $q$Yes, Schleuder is free, open-source software released under the GNU GPL 3.0 license with no licensing cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$What does Schleuder do$q$, $q$Schleuder is a GPG-enabled mailing list manager that automatically encrypts and decrypts messages so subscribers can exchange OpenPGP-encrypted email securely.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Do I need to self-host Schleuder$q$, $q$Yes, Schleuder is self-hosted software; there is no official managed cloud version offered by the project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$What programming language is Schleuder written in$q$, $q$Schleuder is written in Ruby.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Can Schleuder communicate with people who are not on the list$q$, $q$Yes, Schleuder can receive and send messages to non-subscribers, re-encrypting traffic as needed to keep subscriber communication secure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Where is Schleuder developed$q$, $q$Schleuder is developed primarily on the 0xacab.org GitLab instance, with a mirror available on GitHub.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Does Schleuder have a web interface$q$, $q$An optional web interface called schleuder-web can be used alongside Schleuder's API, introduced with the version 3 rewrite.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Secure activist group communication$q$, $q$Privacy-focused organizations and activist groups use Schleuder to run encrypted mailing lists that protect sensitive internal discussions.$q$, $q$Activist and advocacy organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Confidential journalist or NGO coordination$q$, $q$Journalists and NGO teams use Schleuder to coordinate securely over email, including with outside contacts who are not list subscribers.$q$, $q$Journalists and NGO staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Self-hosted encrypted team mailing lists$q$, $q$Technical teams that already self-host infrastructure use Schleuder to add GPG-encrypted list communication without relying on third-party SaaS.$q$, $q$Privacy-conscious technical teams and sysadmins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted GPG-encrypted mailing list manager","Automatic encryption and decryption of list traffic","Remailing to and from non-subscribers","Optional web interface via schleuder-web"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Schleuder is a free, open-source encrypted mailing list manager written in Ruby and licensed under GPL 3.0. It allows subscribers to exchange OpenPGP-encrypted email among themselves while also safely sending and receiving messages from non-subscribers through automatic decryption and re-encryption.$q$, $q$The project is developed on the 0xacab.org GitLab instance, with a mirror on GitHub, and is commonly used by activist groups, privacy-focused organizations, and technical teams that need a self-hosted, encrypted group email solution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Schleuder automatically handles GPG encryption and decryption, header stripping, and format conversions for list traffic, removing the need for every subscriber to manage encryption manually for each message.$q$, $q$Version 3 introduced an internationalized, more robust rewrite along with an API that powers an optional web interface for managing list configuration and subscriptions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Schleuder is entirely free and open source, distributed under the GNU GPL 3.0 license with no commercial pricing tiers, subscriptions, or paid hosting offered by the project itself.$q$, $q$Because it is self-hosted software rather than a SaaS product, users are responsible for their own server, mail transfer agent, and ongoing maintenance costs, but there is no license fee to use Schleuder.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Stack Overflow-style Q&A$q$, $q$Questions, answers, voting, and badges modeled after the familiar Stack Overflow interaction pattern.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Full-text search$q$, $q$Built-in search across questions, answers, and content for fast knowledge retrieval.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Flexible authentication$q$, $q$Social login, OAuth 2.0, and LDAP support for integrating with existing identity systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$SAML SSO and SCIM (Pro)$q$, $q$Enterprise single sign-on via SAML 2.0 and automated user provisioning via SCIM on Pro tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Chat and collaboration integrations$q$, $q$Integrations with Microsoft Teams, Mattermost, and Slack available on Pro tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Self-hosted deployment flexibility$q$, $q$Deployable via Docker, JAR, or native executable on Heroku, AWS, Azure, DigitalOcean, or any VPS.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$REST API$q$, $q$A full REST API for integrating Scoold data with other internal tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Source code access (Pro + Source)$q$, $q$The top license tier grants full Git access to Scoold's source code for custom development.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Free, fully-featured open-source Community edition with no per-user fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$One-time license pricing avoids recurring per-seat SaaS costs at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Flexible self-hosting on any cloud provider or VPS$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Enterprise features like SAML SSO and SCIM available on Pro$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Pro + Source gives full source code ownership for custom development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Requires self-hosting and server maintenance unless using Scoold Cloud$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Scoold Cloud subscription pricing is not publicly listed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Support for Pro licenses is limited to 12 months of free updates post-purchase$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Smaller ecosystem and community compared to mainstream SaaS Q&A/helpdesk tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Is Scoold free to use$q$, $q$Yes, the Scoold Community edition is free and open source under the Apache 2.0 license; paid Pro tiers add enterprise features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$How much does Scoold Pro cost$q$, $q$Scoold Pro costs EUR 499 as a one-time fee per instance, and Pro + Source costs EUR 1,999 one-time, both with 12 months of free updates and support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Does Scoold offer cloud hosting$q$, $q$Yes, Scoold Cloud offers managed subscription-based hosting of Scoold Pro, though specific pricing requires contacting the vendor.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Who develops Scoold$q$, $q$Scoold is developed by Erudika; the project was open-sourced under Apache 2.0 in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Can I self-host Scoold$q$, $q$Yes, Scoold can be self-hosted via Docker, JAR, or native executable on Heroku, AWS, Azure, DigitalOcean, or any VPS.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$What is Pro + Source$q$, $q$Pro + Source is Scoold's top license tier, costing EUR 1,999 one-time, which includes full source code access via Git along with all Pro features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Does Scoold support single sign-on$q$, $q$Yes, SAML 2.0 SSO and SCIM provisioning are available on Scoold Pro and Pro + Source license tiers.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Internal engineering knowledge base$q$, $q$Engineering teams self-host Scoold as an internal Stack Overflow to capture recurring technical questions and answers.$q$, $q$Engineering and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Enterprise Q&A with SSO$q$, $q$Larger organizations use Scoold Pro's SAML SSO and SCIM provisioning to integrate the Q&A platform with existing identity systems.$q$, $q$Enterprise IT and security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Customized internal Q&A platform$q$, $q$Teams needing deep customization purchase Pro + Source to access the full codebase and build bespoke features.$q$, $q$Platform engineering teams with development resources$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Community$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full-text search","Social login, OAuth 2.0, and LDAP","Custom badges and theming","Backup and restore","Unlimited users","REST API"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Scoold Pro$q$, $q$EUR 499 one-time per instance$q$, $q$one-time$q$, NULL, $q$["Everything in Community","SAML 2.0 SSO and SCIM provisioning","@mentions and file uploads","Teams, Mattermost, and Slack integrations","Unlimited spaces and admins","12 months of free updates and support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Pro + Source$q$, $q$EUR 1,999 one-time per instance$q$, $q$one-time$q$, NULL, $q$["Everything in Pro","Full source code access via Git","Custom feature development allowed","Architecture consulting","VAT invoicing available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$Scoold Cloud$q$, $q$Subscription, price not publicly listed$q$, $q$subscription$q$, NULL, $q$["Managed hosting of Scoold Pro","No self-hosting required"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scoold is a self-hosted, open-source Q&A and knowledge-sharing platform built by Erudika, modeled on the Stack Overflow experience but designed for internal team use. The underlying project dates back to 2008 and 2012, and was fully open-sourced under Apache 2.0 in 2017.$q$, $q$It can be deployed on Heroku, DigitalOcean, AWS, Azure, or any VPS as a Docker container, JAR, or native executable, giving engineering and IT teams full control over hosting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free Community edition includes full-text search, social login/OAuth2/LDAP, custom badges, theming, backup and restore, email notifications, unlimited users, and a REST API.$q$, $q$Paid Pro tiers add SAML 2.0 SSO, SCIM provisioning, @mentions, file uploads, integrations with Teams, Mattermost, and Slack, advanced security notifications, and unlimited spaces and admins.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scoold uses one-time license pricing rather than per-seat subscriptions for self-hosted tiers: Scoold Pro costs EUR 499 one-time per instance, and Pro + Source costs EUR 1,999 one-time per instance and includes full source code access.$q$, $q$Scoold Cloud offers managed, subscription-based hosting of Scoold Pro for teams that prefer not to self-host, though specific cloud subscription prices are not listed publicly and require contacting the vendor.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c4424b7-aba0-4e04-9853-edd33d4b7072', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
