INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Custom domains and branding$q$, $q$Custom domain support and custom CSS/scripts for on-brand quiz funnels on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Data enrichment and split testing$q$, $q$Pro-tier tools for enriching lead data and A/B testing quiz funnel variations.$q$, 6);
