INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Advanced features like data enrichment and split testing are reserved for the Pro tier and above$q$, 2);
