INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$What is ScoreApp used for$q$, $q$ScoreApp is used to build interactive quizzes and scorecards for lead generation, lead qualification, and customer engagement marketing funnels.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Does ScoreApp have a free plan$q$, $q$Yes, ScoreApp offers a free plan with 1 live scorecard and up to 10 monthly responses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$How much does ScoreApp cost$q$, $q$Paid plans range from $39/month for Starter to $149/month for Pro, with roughly 25 percent off on annual billing, plus a custom-priced Enterprise plan starting around $799/month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Who founded ScoreApp$q$, $q$ScoreApp was founded in 2019 by Steven Oddy and Daniel Priestley under the company Hyper Targeted Marketing Limited.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Where is ScoreApp based$q$, $q$ScoreApp's parent company, Hyper Targeted Marketing Limited, is based in Watford, England.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Does ScoreApp integrate with a CRM$q$, $q$Yes, CRM connectivity is included on every ScoreApp plan, including the free tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$What is included in the ScoreApp Enterprise plan$q$, $q$Enterprise includes unlimited user seats, VIP support, tailored onboarding, granular permissions, and single sign-on, with custom infinitely scalable pricing.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Lead generation quiz funnels$q$, $q$Marketers build interactive quizzes to attract and capture qualified leads in place of static contact forms.$q$, $q$Marketers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Coaching and consulting client qualification$q$, $q$Coaches and consultants use scorecards to qualify prospects and personalize follow-up based on quiz results.$q$, $q$Coaches and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Service business sales enablement$q$, $q$Service businesses use dynamic result pages and data enrichment to segment audiences and prioritize sales outreach.$q$, $q$Service-based business owners and sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["1 live scorecard","10 monthly responses","AI quiz builder and AI marketing assistant","Unlimited landing pages","CRM connectivity"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Starter$q$, $q$$39/month ($30/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["3 live scorecards","100 monthly responses","1 user","Unlimited quiz questions and jump logic","Export capabilities"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Business$q$, $q$$99/month ($75/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["10 live scorecards","1,000 monthly responses","3 users","Custom domain and abandonment emails","Advanced insights and audience segmentation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Pro$q$, $q$$149/month ($112/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["30 live scorecards","3,000 monthly responses","5 users","Data enrichment","Split testing"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$Enterprise$q$, $q$From $799/month, custom$q$, $q$custom$q$, NULL, $q$["Unlimited user seats","VIP support","Tailored onboarding","Granular permissions and SSO"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ScoreApp is a quiz funnel marketing platform built by Hyper Targeted Marketing Limited, founded in 2019 by Steven Oddy and Daniel Priestley and based in Watford, England. It helps businesses build interactive quizzes and scorecards to attract, qualify, and convert leads.$q$, $q$The platform is aimed at marketers, coaches, consultants, and service businesses that want to replace static lead-capture forms with engaging, data-driven quiz experiences tied into their existing CRM and marketing stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ScoreApp includes an AI quiz builder and AI marketing assistant, unlimited quiz questions, jump logic for branching paths, multiple question types, unlimited landing pages, dynamic personalized result pages, and CRM connectivity across all plans, including the free tier.$q$, $q$Higher tiers add custom domains, abandonment emails, advanced insights and audience segmentation, custom CSS/scripts, analytics pixel integrations, dynamic PDF reports, data enrichment, and split testing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e479f0c5-74e4-41f4-aa19-bfdcda30ccd9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ScoreApp offers a free plan (1 live scorecard, 10 monthly responses) plus four paid tiers: Starter at $39/month, Business at $99/month, Pro at $149/month, and a custom-priced Enterprise plan starting around $799/month, each with roughly a 25 percent discount for annual billing.$q$, $q$All paid plans include a 14-day money-back guarantee, and plan limits scale by number of live scorecards, monthly responses, and included user seats.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Project and task management$q$, $q$Core project planning tools including Gantt charts and task tracking across teams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Quoting and invoicing$q$, $q$Built-in quote generation and invoicing tied directly to project and client data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Resource planning and timesheets$q$, $q$Resource planner and timesheet tools for allocating staff and tracking billable hours on Performance and above.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Financial and utilization reporting$q$, $q$Financial reports, utilization reports, and revenue forecasting for agency profitability tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Retainer and budget management$q$, $q$Project budgets and retainer management tools available from the Growth plan upward.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Sales pipeline management$q$, $q$Built-in sales pipeline and supplier management tools on the Performance tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Role-based labor costing$q$, $q$Labor costs tracked by role to support accurate project profitability analysis.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Enterprise controls$q$, $q$Company-wide budgets, approval flows, SSO, and user provisioning available on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$All-in-one platform reduces the need for separate PM, billing, and CRM tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Deep professional-services features like retainers and role-based costing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Backed by venture funding and recognized as a fast-growing company$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Multi-currency support suited to international agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$14-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Minimum of 5 user seats required, unsuitable for solo users or very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Advanced resourcing and forecasting features locked behind higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Per-seat pricing can get expensive quickly for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Premium onboarding is a significant additional cost at $1,699+$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$What is Scoro used for$q$, $q$Scoro is used by agencies, consultancies, and professional services firms to manage projects, resources, billing, and reporting in one integrated platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$How much does Scoro cost$q$, $q$Scoro's Core plan starts at $19.90 per user per month, with Growth at $32.90 and Performance at $49.90 per user per month, all requiring a minimum of 5 seats; Enterprise is custom priced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$When was Scoro founded$q$, $q$Scoro was founded in 2013 in Tallinn, Estonia, by Fred Krieger, and is now headquartered in London, England.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Does Scoro require a minimum number of users$q$, $q$Yes, all Scoro plans require a minimum of 5 user seats.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Does Scoro offer a free trial$q$, $q$Yes, Scoro offers a 14-day free trial with no credit card required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$What is included in Scoro's Enterprise plan$q$, $q$Enterprise adds company-wide budgets, approval flows, multi-account reporting, single sign-on, user provisioning, and FTP integration, at custom pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Has Scoro raised funding$q$, $q$Yes, Scoro raised a $16.4 million Series B funding round in 2021 led by Kennet Partners.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Agency project and billing management$q$, $q$Creative and marketing agencies use Scoro to manage client projects, timesheets, and invoicing in one platform.$q$, $q$Marketing and creative agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Consultancy resource planning$q$, $q$Consulting firms use Scoro's resource planner and role-based labor costing to allocate staff and track profitability.$q$, $q$Consultancies and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$IT services retainer management$q$, $q$IT services companies use Scoro's retainer management and financial reporting to track recurring client engagements.$q$, $q$IT services and managed service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Core$q$, $q$$19.90/user/month$q$, $q$monthly (annual billing available)$q$, NULL, $q$["Project and task management","Gantt charts","Contacts and CRM","Quotes and invoicing","Dashboards and work reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Growth$q$, $q$$32.90/user/month$q$, $q$monthly (annual billing available)$q$, NULL, $q$["Everything in Core","Project budgets","Retainer management","Role-based labor costs","Financial and utilization reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Performance$q$, $q$$49.90/user/month$q$, $q$monthly (annual billing available)$q$, NULL, $q$["Everything in Growth","Resource planner and timesheets","Task matrix and price lists","Revenue forecasting","Sales pipeline and supplier management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Everything in Performance","Company-wide budgets and approval flows","Multi-account reporting","Single sign-on and user provisioning","FTP integration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scoro is a professional services automation (PSA) and work management platform founded in 2013 in Tallinn, Estonia by Fred Krieger, now headquartered in London, England with offices in New York, Tallinn, Riga, and Vilnius. It targets consultancies, agencies, and IT firms that need projects, resourcing, and finances managed in one system.$q$, $q$The company raised a $16.4 million Series B round in 2021 led by Kennet Partners and has been recognized on both the Deloitte Technology Fast 500 and the Inc. 5000 lists of fast-growing companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scoro combines project and task management, Gantt charts, quoting and invoicing, CRM/contact management, dashboards, and work reporting as its baseline capability set.$q$, $q$Higher tiers add project budgeting, retainer management, resource planning, timesheets, revenue forecasting, sales pipeline management, and supplier management for more advanced agency operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('534a63de-bd62-4e46-81b3-354224a9fcb1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scoro prices per user per month across four tiers: Core at $19.90, Growth at $32.90, and Performance at $49.90, each requiring a minimum of 5 user seats, with a custom-priced Enterprise tier for larger organizations.$q$, $q$Optional premium onboarding starts at $1,699 for a six-week engagement, and Scoro offers a 14-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Application performance traces$q$, $q$Tracks response times and performance bottlenecks across Ruby, Python, PHP, Node.js, and Elixir applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$N+1 query and memory bloat detection$q$, $q$Specialized detection for common performance issues like N+1 database queries and memory bloat.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Integrated error monitoring$q$, $q$Combines error tracking with performance traces in a single dashboard since its June 2021 expansion.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Log management$q$, $q$Centralized log storage and search alongside performance and error data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Unlimited users and applications$q$, $q$All plans, including free, support unlimited team members and monitored applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Transaction-based pricing tiers$q$, $q$Costs scale by monthly transaction volume rather than per-seat or per-host fees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Priority and premier support$q$, $q$Priority support on the Production Ready plan and premier support with SLA reporting on Enterprise.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$SSO and security audits (Enterprise)$q$, $q$Enterprise plan adds single sign-on, custom retention, and formal security audits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Unlimited users and applications on every plan, including free$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Transaction-based pricing avoids per-seat cost scaling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Specialized, mature support for Ruby on Rails plus other major languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Combines APM, error monitoring, and logs in a single product$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Free tier available with a meaningful transaction allowance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Log retention on paid non-enterprise plans is limited to 14 days$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Errors are capped at 5,000 on most tiers unless purchasing add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Smaller feature breadth than large APM platforms like Datadog or New Relic$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Enterprise-grade features such as SSO and SLA reporting require custom Enterprise pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$What is Scout APM used for$q$, $q$Scout APM (Scout Monitoring) is used to monitor application performance, errors, and logs for Ruby, Python, PHP, Node.js, and Elixir applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Is Scout APM free$q$, $q$Yes, Scout offers a free plan with 300,000 monthly transactions, 5,000 errors, and 1 GB of log storage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$How is Scout APM priced$q$, $q$Scout is priced based on monthly transaction volume rather than per user, with plans ranging from $19/month to $299/month plus a custom Enterprise tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$When was Scout APM founded$q$, $q$Scout APM was founded in 2008 and is headquartered in Denver, Colorado.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Does Scout APM support Rails specifically$q$, $q$Yes, Scout has specialized in Ruby on Rails performance monitoring since its founding, including detecting N+1 queries and memory bloat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Does Scout APM include error monitoring$q$, $q$Yes, Scout added integrated error monitoring alongside performance tracing in June 2021.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Is there a limit on users with Scout APM plans$q$, $q$No, all Scout plans, including the free tier, include unlimited users and unlimited applications.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Ruby on Rails performance monitoring$q$, $q$Rails development teams use Scout to detect N+1 queries, memory bloat, and slow endpoints in production.$q$, $q$Ruby on Rails developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Multi-language application monitoring$q$, $q$Teams running Python, PHP, Node.js, or Elixir applications use Scout for unified performance and error tracking.$q$, $q$Backend engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Cost-predictable APM for small teams$q$, $q$Smaller engineering teams use Scout's transaction-based pricing to get APM without per-seat licensing costs.$q$, $q$Startups and small engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["300K monthly transactions","1 GB logs","5,000 errors","Full API access","Unlimited users and apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Production Ready$q$, $q$$59/month (annual) or $98/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["1.2M monthly transactions","50,000 errors","30 GB log storage, 14-day retention","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom transaction volume","Custom log storage and retention","SSO","Security audit and SLA reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scout APM, now branded Scout Monitoring, is an application performance monitoring tool founded in 2008 and headquartered in Denver, Colorado. It began with a strong focus on Ruby on Rails monitoring and has since expanded to support Python, PHP, Node.js, and Elixir applications.$q$, $q$The company is privately held with an estimated 11 to 50 employees, and its customers have historically included SaaS companies such as Expedia, Chargify, Liftopia, and MindBody. In June 2021, Scout added integrated error monitoring alongside its core performance tracing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scout Monitoring tracks application traces, errors, and logs in a single dashboard, with particular strength in isolating N+1 database queries and memory bloat issues common in Rails and other web frameworks.$q$, $q$All plans, including the free tier, include unlimited users and unlimited monitored applications, with cost scaling purely by transaction volume, error count, and log storage rather than per-seat licensing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66aef3e8-fdf4-4871-a16f-ccd3d0ecfe6d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scout offers a free plan with 300,000 monthly transactions, 5,000 errors, and 1 GB of logs, and a 'Production Ready' plan at $59/month (billed annually) or $98/month (billed monthly) with 1.2 million transactions and 30 GB of log storage.$q$, $q$Additional build-your-own tiers range from Startup at $19/month up to Large at $299/month based on transaction volume, with add-ons available for extra errors and log storage, plus a custom-priced Enterprise tier with SSO and SLA reporting.$q$]::text[], 2);
