-- ── Scaleway ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Scaleway is a French cloud infrastructure provider offering compute, storage, AI, and managed services with transparent, pay-as-you-go pricing.$q$, short_description),
  pricing_model = COALESCE($q$Pay-as-you-go / usage-based, plus dedicated server plans$q$, pricing_model),
  starting_price = COALESCE($q$From about EUR 4.99/month for entry-level Dedibox dedicated servers; cloud instances billed per-second from fractions of a euro per hour$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE($q$500+ employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Scaleway Review 2026 - Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Scaleway costs in 2026, who it is for, and how its cloud compute, storage, and AI infrastructure compares to other European cloud providers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scaleway is a European cloud computing and infrastructure provider headquartered in Paris, France, and operated as a majority-owned subsidiary of the Iliad Group, the telecom conglomerate founded by Xavier Niel. The company traces its roots to 1999, when it launched as Online SAS (Online.net), a web hosting and domain registration business; in April 2015 its infrastructure-as-a-service offering was rebranded as Scaleway, and the brand has since expanded into a full public cloud platform. Scaleway runs its own data centers across Paris, Amsterdam, and Warsaw, and reports serving more than 25,000 businesses across roughly 160 countries, with a workforce that has grown past 500 employees. Its product catalog spans bare-metal Dedibox dedicated servers, virtual compute instances (categorized into Development, General Purpose, Compute Optimized, and Memory Optimized ranges), GPU instances for AI and machine learning workloads, managed Kubernetes, serverless functions and containers, object and block storage, managed databases, and networking services such as load balancers and private networks. Pricing is usage-based and marketed as transparent, with dedicated Dedibox servers starting around EUR 4.99 per month and cloud compute instances billed by the second at low hourly rates, positioning Scaleway as a cost-competitive alternative to AWS, Google Cloud, and Azure, particularly for European companies with data-sovereignty requirements under GDPR. As part of the Iliad Group, Scaleway has increasingly emphasized sovereign and AI-focused infrastructure, including GPU clusters for AI training and inference, and has pursued acquisitions (such as data platform company Saagie) to expand its AI and data engineering capabilities. The company has also explored spinning off parts of its data center operations into a standalone entity. For a directory like gappsy.com, Scaleway is best categorized alongside other cloud infrastructure and hosting providers (AWS, Google Cloud, DigitalOcean, Hetzner, OVHcloud) as a mid-size, France-based, developer-oriented cloud with a strong emphasis on European sovereignty, straightforward pricing, and growing AI infrastructure offerings. It is not a SaaS application but core infrastructure (IaaS/PaaS), so it is most relevant to developers, DevOps teams, and companies evaluating cloud hosting alternatives to the US hyperscalers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '71f03e14-432c-435c-8c0e-ef2bed2b9907';

