-- ── Sched ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sched is event and conference scheduling software that helps organizers build personalized agendas, manage speakers, and handle registration for in-person, virtual, and hybrid events.$q$, short_description),
  pricing_model = COALESCE($q$Annual subscription tiers plus a free plan for small events$q$, pricing_model),
  starting_price = COALESCE($q$Launch plan from about $600/year$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Los Angeles, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sched Review 2026 - Event Scheduling Software Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$An overview of Sched's event and conference scheduling platform, including pricing tiers, key features, and what kinds of events it fits best.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sched, found at sched.com, is event and conference scheduling software founded in 2008 and based in Los Angeles, California. It is built specifically for organizers of conferences, conventions, festivals, and other multi-session events who need to manage complex agendas, speaker lineups, sponsor profiles, and attendee registration in one platform. Core functionality includes a personalized schedule builder that lets attendees create their own agenda from many concurrent sessions, a web and mobile app for browsing the event, speaker and session profile pages, registration and ticketing tools, call-for-papers/session submission workflows, attendee networking features, badge printing, and lead retrieval tools for sponsors and exhibitors. Sched structures its pricing into named annual plans rather than simple monthly SaaS tiers: the Launch plan starts at roughly $600 per year, Boost (the most popular tier) runs about $1,500 per year and adds attendee networking, attendance tracking, customizable badges, sponsor profiles, and enhanced call-for-papers tools, and Ultra costs around $3,900 per year and adds onboarding and training, priority support, custom reporting, secret sessions, and advanced lead retrieval, with Sched claiming over $8,000 in bundled feature and savings value at that tier. An Enterprise tier is available with custom pricing for organizations that need on-premise hosting, custom feature development, or dedicated premium agent support. All plans include unlimited events, and smaller events (roughly under 50 attendees) can often run free or at reduced cost, with additional discounts offered for nonprofits (up to 50 percent off), educational institutions (33 percent), government organizations (17 percent), and startups (17 percent). Sched also offers a 30-day free trial and a 60-day money-back guarantee. Because pricing scales with plan tier and attendee volume rather than strictly per-seat, Sched tends to appeal most to conference and event organizers, associations, and marketing/events teams running recurring multi-track events rather than one-off small meetings. It is distinct from general-purpose scheduling and calendar-booking tools (such as appointment schedulers), focusing instead on the specialized workflow of building and publishing a full multi-day event agenda with speaker and sponsor management baked in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3ddaae47-3573-4276-bcc8-70bfee3048e2';

