-- ── Schleuder ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Schleuder is a free, open-source GPG-encrypted mailing list manager that lets subscribers exchange OpenPGP-encrypted email and communicate securely with non-subscribers.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Schleuder Review 2026 - Open-Source Encrypted Mailing List Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Schleuder provides GPG-encrypted mailing lists for privacy-focused groups, its features, self-hosting requirements, and open-source licensing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Schleuder is a free, open-source encrypted mailing list manager built specifically for groups that need to communicate over email with strong end-to-end privacy guarantees. Written in Ruby and released under the GNU General Public License version 3.0, it functions as a GPG-enabled mailing list gateway: it automatically decrypts incoming OpenPGP-encrypted messages, re-encrypts and distributes them to all subscribers on a list, and can also receive and re-encrypt messages sent by non-subscribers so that a group can safely correspond with outside contacts without exposing individual subscriber keys or requiring every participant to manually manage encryption. Version 3 of Schleuder represented a complete rewrite of the project aimed at making it more robust, flexible, and internationalized, and it introduced an API that can back an optional web interface (schleuder-web) for managing list settings and subscriptions. The project is developed and hosted primarily on the 0xacab.org GitLab instance run by the Riseup collective, with a mirror maintained on GitHub for visibility, and prebuilt packages are available for Debian (including current stable releases such as bullseye and bookworm), CentOS, and Arch Linux to simplify self-hosted installation. As with most privacy and activist-oriented infrastructure tools in this space, there is no commercial company behind Schleuder, no pricing tiers, and no vendor headquarters or employee count to report; it is maintained by volunteer contributors within the privacy and digital-security tooling community, historically associated with groups like Nadir and the broader European hacktivist and anti-surveillance infrastructure scene. Because it requires server administration skills to deploy (a mail transfer agent, Ruby runtime, and GPG key management), Schleuder is best suited to technically capable teams, activist organizations, journalists, NGOs, and privacy-conscious communities that need a secure group email channel and are willing to self-host rather than rely on a commercial encrypted communication SaaS product. For a directory like gappsy.com, Schleuder belongs in categories such as open-source software, email and communication privacy tools, and self-hosted infrastructure, and it should be described accurately as free software with no company behind it rather than assigned invented pricing or company facts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8d8b2b44-477b-41ea-a9d3-9c1a6fd53b08';

