-- ── Scoold ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Scoold is a self-hosted, open-source Q&A and knowledge-sharing platform for teams, modeled after Stack Overflow, with a free community edition and paid Pro tiers.$q$, short_description),
  pricing_model = COALESCE($q$Free open-source core with one-time license fees for Pro tiers and subscription-based cloud hosting$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community edition); Scoold Pro from EUR 499 one-time per instance$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Scoold Review 2026 - Self-Hosted Q&A Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Scoold's Stack Overflow-style Q&A platform works, its free open-source edition, Pro license pricing, and Scoold Cloud hosting options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scoold is a self-hosted, open-source Q&A and knowledge-sharing platform designed to give internal teams a Stack Overflow-style experience for their own questions, answers, and documentation. It is developed by Erudika and traces back to a project originally created in 2008 as a social network for schools, which was released in 2012, then refactored, repackaged, and fully open-sourced in 2017 under the Apache 2.0 license. The platform is deployable anywhere, including Heroku, DigitalOcean, AWS, Azure, or any VPS, and ships as a Docker container, a runnable JAR, or a native executable, giving teams flexibility over where they host their knowledge base. Core functionality includes full-text search, social login and OAuth 2.0 or LDAP authentication, custom badges and gamification, theming and white-label branding, backup and restore tools, email notifications, unlimited users, and a REST API for integrations, all included free in the open-source Community edition. Scoold's commercial model is built around one-time license fees rather than recurring subscriptions for its self-hosted Pro tiers: Scoold Pro costs EUR 499 as a one-time fee per instance and adds SAML 2.0 single sign-on, SCIM user provisioning, @mentions, file uploads, integrations with Microsoft Teams, Mattermost, and Slack, advanced security notifications, unlimited spaces and admins, approved domain restrictions, and account suspension controls, with free updates and support for 12 months after purchase. A higher Pro + Source tier costs EUR 1,999 as a one-time fee and additionally grants full source code access via Git, allows custom feature development, and includes architecture consulting along with VAT invoicing for businesses. For teams that don't want to self-host, Scoold Cloud offers managed hosting of Scoold Pro on a subscription basis, though exact cloud subscription pricing is not published on the main pricing page and requires contacting the vendor. All Pro licenses come with a 14-day money-back guarantee, and every tier supports unlimited users regardless of price. This one-time-license-plus-optional-cloud model differentiates Scoold from most modern SaaS knowledge-base tools, making it particularly attractive to engineering and IT teams that prefer to self-host internal tools, avoid per-seat SaaS costs at scale, and want full control and eventual source-code ownership over their internal Q&A platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4c4424b7-aba0-4e04-9853-edd33d4b7072';

