-- ── ScoreApp ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ScoreApp is a quiz funnel marketing platform that helps businesses build interactive quizzes and scorecards to generate leads, qualify prospects, and drive sales.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with tiered monthly/annual subscription plans$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Starter plan from $39/month (or $30/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Watford, England, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ScoreApp Review 2026 - Quiz Funnel Marketing Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how ScoreApp's quiz funnel marketing platform works, its pricing plans from free to Enterprise, and its AI-powered quiz and lead generation features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ScoreApp is a quiz funnel marketing platform built by Hyper Targeted Marketing Limited, a company incorporated in November 2019 and based in Watford, England, and co-founded by Steven Oddy and Daniel Priestley. The product is designed to help businesses attract, qualify, and convert leads through interactive quizzes and scorecards rather than static lead-capture forms, supporting the full customer journey from initial attraction through onboarding and ongoing engagement. Core capabilities include an AI quiz builder and AI marketing assistant, unlimited quiz questions, jump logic for branching question paths, multiple question types, unlimited landing pages, dynamic personalized result pages, and CRM connectivity for pushing captured leads into a business's existing sales and marketing stack. ScoreApp uses a freemium pricing model with five tiers. The Free plan allows one live scorecard and up to 10 monthly responses. The Starter plan costs $39 per month billed monthly or about $30 per month billed annually (a 25 percent annual discount), supporting 3 live scorecards, 100 monthly responses, and 1 user, and adds unlimited quiz questions, jump logic, and export capabilities. The Business plan, marketed as the best-value tier, costs $99 per month monthly or about $75 per month annually, supporting 10 live scorecards, 1,000 monthly responses, and 3 users, and adds a custom domain, abandonment emails, advanced insights, custom CSS and scripts, Google Analytics and Facebook Pixel integration, dynamic PDF reports, and audience segmentation. The Pro plan costs $149 per month monthly or about $112 per month annually, supporting 30 live scorecards, 3,000 monthly responses, and 5 users, and adds data enrichment and split testing on top of everything in Business. An Enterprise plan starts around $799 per month with custom, infinitely scalable pricing, unlimited user seats, VIP support, tailored onboarding, granular permissions, and single sign-on. All paid plans come with a 14-day money-back guarantee. ScoreApp has reportedly grown to roughly $3.2 million in annual recurring revenue without raising outside venture capital funding, according to third-party revenue-tracking sources. It is most relevant to marketers, coaches, consultants, and service businesses looking to use interactive quiz-based lead generation and qualification funnels rather than traditional static forms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e479f0c5-74e4-41f4-aa19-bfdcda30ccd9';

